import { useCallback, useEffect, useMemo, useState } from "react";
import AuthPanel from "./components/AuthPanel";
import Upload from "./components/Upload";
import Search from "./components/Search";
import FileList from "./components/FileList";
import { confirmSignUp, getSession, signIn, signOut, signUp } from "./auth";

const API_URL = process.env.REACT_APP_API_URL;
const MAX_FILE_SIZE_BYTES = 25 * 1024 * 1024;

const formatDateTime = (value) =>
  new Intl.DateTimeFormat("en-US", {
    dateStyle: "medium",
    timeStyle: "short"
  }).format(new Date(value));

const formatBytes = (value) => {
  if (!Number.isFinite(value) || value <= 0) {
    return "0 B";
  }

  const sizes = ["B", "KB", "MB", "GB"];
  const index = Math.min(Math.floor(Math.log(value) / Math.log(1024)), sizes.length - 1);
  const amount = value / 1024 ** index;

  return `${amount >= 10 || index === 0 ? amount.toFixed(0) : amount.toFixed(1)} ${sizes[index]}`;
};

function App() {
  const [session, setSession] = useState(null);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [isAuthSubmitting, setIsAuthSubmitting] = useState(false);
  const [authError, setAuthError] = useState("");
  const [files, setFiles] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgressLabel, setUploadProgressLabel] = useState("");
  const [searchValue, setSearchValue] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [deletingFile, setDeletingFile] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [activeQuery, setActiveQuery] = useState("");

  const dashboardStats = useMemo(() => {
    const totalFiles = files.length;
    const totalStorage = files.reduce((sum, file) => sum + (file.size || 0), 0);
    const latestUpload = files[0]?.uploadedAt;

    return {
      totalFiles,
      totalStorage: formatBytes(totalStorage),
      latestUpload: latestUpload ? formatDateTime(latestUpload) : "No uploads yet"
    };
  }, [files]);

  const authenticatedFetch = async (path, options = {}) => {
    if (!API_URL) {
      throw new Error("REACT_APP_API_URL is not configured.");
    }

    if (!session?.token) {
      throw new Error("You must be signed in to use FileFinder.");
    }

    const headers = new Headers(options.headers || {});
    headers.set("Authorization", session.token);

    return fetch(`${API_URL}${path}`, {
      ...options,
      headers
    });
  };

  const fetchFiles = useCallback(async () => {
    if (!session?.token) {
      setFiles([]);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const response = await authenticatedFetch("/files");
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Failed to load files.");
      }

      setFiles(data.files || []);
    } catch (requestError) {
      setError(requestError.message);
    } finally {
      setIsLoading(false);
    }
  }, [session]);

  useEffect(() => {
    const initializeSession = async () => {
      try {
        setSession(await getSession());
      } catch (sessionError) {
        setAuthError(sessionError.message);
      } finally {
        setIsAuthLoading(false);
      }
    };

    initializeSession();
  }, []);

  useEffect(() => {
    if (session?.token) {
      fetchFiles();
    }
  }, [fetchFiles, session]);

  const handleResetSearch = async () => {
    setSearchValue("");
    setActiveQuery("");
    await fetchFiles();
  };

  const handleUpload = async (file, customName) => {
    setIsUploading(true);
    setUploadProgressLabel("Requesting secure upload URL...");
    setError("");
    setMessage("");

    try {
      if (file.size > MAX_FILE_SIZE_BYTES) {
        throw new Error("File is larger than the 25 MB upload limit.");
      }

      const resolvedName = customName.trim() || file.name;

      const presignResponse = await authenticatedFetch("/upload", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          action: "presign",
          originalFilename: file.name,
          displayName: resolvedName,
          contentType: file.type
        })
      });

      const presignData = await presignResponse.json();

      if (!presignResponse.ok) {
        throw new Error(presignData.message || "Failed to create upload URL.");
      }

      setUploadProgressLabel("Uploading file directly to Amazon S3...");
      const uploadResponse = await fetch(presignData.uploadUrl, {
        method: "PUT",
        headers: {
          "Content-Type": file.type || "application/octet-stream"
        },
        body: file
      });

      if (!uploadResponse.ok) {
        throw new Error("Failed to upload file to S3.");
      }

      setUploadProgressLabel("Saving metadata in DynamoDB...");
      const completionResponse = await authenticatedFetch("/upload", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          action: "complete",
          fileId: presignData.fileId,
          displayName: presignData.displayName,
          originalFilename: presignData.originalFilename,
          s3Key: presignData.fileKey,
          uploadedAt: new Date().toISOString(),
          size: file.size,
          contentType: file.type || "application/octet-stream"
        })
      });

      const completionData = await completionResponse.json();

      if (!completionResponse.ok) {
        throw new Error(completionData.message || "Failed to save file metadata.");
      }

      setMessage(`Uploaded ${presignData.displayName} successfully.`);
      setUploadProgressLabel("");
      setSearchValue("");
      setActiveQuery("");
      await fetchFiles();
      return true;
    } catch (uploadError) {
      setError(uploadError.message);
      return false;
    } finally {
      setIsUploading(false);
      setUploadProgressLabel("");
    }
  };

  const handleSearch = async (query) => {
    const trimmedQuery = query.trim();

    setSearchValue(query);
    setActiveQuery(query);
    setError("");
    setMessage("");

    if (!trimmedQuery) {
      await fetchFiles();
      return;
    }

    setIsLoading(true);
    setIsSearching(true);

    try {
      const response = await authenticatedFetch(
        `/search?filename=${encodeURIComponent(trimmedQuery)}`
      );
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Failed to search files.");
      }

      setFiles(data.files || []);
    } catch (searchError) {
      setError(searchError.message);
    } finally {
      setIsLoading(false);
      setIsSearching(false);
    }
  };

  const handleDelete = async (fileId, displayName) => {
    setError("");
    setMessage("");
    setDeletingFile(fileId);

    try {
      const response = await authenticatedFetch("/delete", {
        method: "DELETE",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ fileId })
      });
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Failed to delete file.");
      }

      setMessage(`Deleted ${displayName} successfully.`);

      if (activeQuery.trim()) {
        await handleSearch(activeQuery);
      } else {
        await fetchFiles();
      }
    } catch (deleteError) {
      setError(deleteError.message);
    } finally {
      setDeletingFile("");
    }
  };

  const handleQuickSearchChange = async (query) => {
    setSearchValue(query);

    if (!query.trim()) {
      await handleResetSearch();
    }
  };

  const handleAuthAction = async (action) => {
    setAuthError("");
    setIsAuthSubmitting(true);

    try {
      const nextSession = await action();

      if (nextSession?.token) {
        setSession(nextSession);
      }
    } catch (actionError) {
      setAuthError(actionError.message || "Authentication failed.");
    } finally {
      setIsAuthSubmitting(false);
    }
  };

  if (isAuthLoading) {
    return <div className="auth-loading">Loading secure workspace...</div>;
  }

  if (!session) {
    return (
      <AuthPanel
        onSignIn={(payload) => handleAuthAction(() => signIn(payload))}
        onSignUp={(payload) => handleAuthAction(() => signUp(payload))}
        onConfirm={(payload) => handleAuthAction(() => confirmSignUp(payload))}
        error={authError}
        isSubmitting={isAuthSubmitting}
      />
    );
  }

  return (
    <div className="app-shell">
      <main className="app-card">
        <section className="hero">
          <div className="hero-copy-block">
            <p className="eyebrow">Authenticated File Intelligence</p>
            <h1>FileFinder</h1>
            <p className="hero-copy">
              Your private serverless workspace for secure uploads, custom file names,
              searchable metadata, and access-controlled cleanup.
            </p>
            <div className="hero-actions">
              <button type="button" className="primary-button" onClick={fetchFiles}>
                Refresh Workspace
              </button>
              <button
                type="button"
                className="secondary-button"
                onClick={() => {
                  signOut();
                  setSession(null);
                  setFiles([]);
                }}
              >
                Sign Out
              </button>
              <div className="hero-note">
                Signed in as <span>{session.name || session.email || session.username}</span>
              </div>
            </div>
          </div>

          <div className="hero-badge-grid">
            <div className="hero-badge-card">
              <span className="hero-badge-label">Files Indexed</span>
              <strong>{dashboardStats.totalFiles}</strong>
            </div>
            <div className="hero-badge-card">
              <span className="hero-badge-label">Tracked Storage</span>
              <strong>{dashboardStats.totalStorage}</strong>
            </div>
            <div className="hero-badge-card">
              <span className="hero-badge-label">Latest Activity</span>
              <strong>{dashboardStats.latestUpload}</strong>
            </div>
          </div>
        </section>

        <section className="overview-grid">
          <article className="metric-card">
            <span className="metric-title">Identity-Protected API</span>
            <p>Every request is authorized with Cognito, and each user sees only their own files.</p>
          </article>
          <article className="metric-card">
            <span className="metric-title">Custom File Naming</span>
            <p>Upload with the original filename or give each file a cleaner name for your workspace.</p>
          </article>
          <article className="metric-card">
            <span className="metric-title">Operational Safety</span>
            <p>Delete actions are scoped to the authenticated owner and synchronized across metadata and storage.</p>
          </article>
        </section>

        <section className="panel-grid">
          <Upload
            onUpload={handleUpload}
            isUploading={isUploading}
            uploadProgressLabel={uploadProgressLabel}
            maxFileSizeLabel={formatBytes(MAX_FILE_SIZE_BYTES)}
          />
          <Search
            onSearch={handleSearch}
            onReset={handleResetSearch}
            onSearchValueChange={handleQuickSearchChange}
            query={searchValue}
            isSearching={isSearching}
            activeQuery={activeQuery}
          />
        </section>

        {(message || error) && (
          <div className={`status-banner ${error ? "error" : "success"}`}>
            {error || message}
          </div>
        )}

        <FileList
          files={files}
          isLoading={isLoading}
          onDelete={handleDelete}
          deletingFile={deletingFile}
          activeQuery={activeQuery}
          formatBytes={formatBytes}
          formatDateTime={formatDateTime}
        />
      </main>
    </div>
  );
}

export default App;
